const perplexityData = $input.item.json;
const prepData = $('Prepare Perplexity Request').item.json;

const research = perplexityData.choices ? perplexityData.choices[0].message.content : JSON.stringify(perplexityData);

const prompt = 'You are an ICP specialist for social media marketing. Based on the following market research, create a comprehensive Ideal Customer Profile.\n\nBusiness: ' + prepData.business_url + '\nIndustry: ' + prepData.industry + '\nMarket Research: ' + research + '\n\nReturn a JSON object with keys: icp_summary, demographics, psychographics, content_preferences, competitors, content_opportunities, recommended_hashtags.\n\nReturn ONLY valid JSON, no markdown.';

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  messages: [{ role: 'user', content: prompt }]
});

return { json: { apiBody: body, user_id: prepData.user_id, business_url: prepData.business_url, industry: prepData.industry } };

const input = $input.item.json;
const prepData = $('Prepare ICP Prompt').item.json;

let icpContent = '';
try {
  icpContent = input.content[0].text;
} catch(e) {
  icpContent = JSON.stringify(input);
}

let icpParsed = {};
try {
  icpParsed = JSON.parse(icpContent);
} catch(e) {
  icpParsed = { raw: icpContent };
}

return {
  json: {
    user_id: prepData.user_id,
    business_url: prepData.business_url,
    industry: prepData.industry,
    icp_summary: icpParsed.icp_summary || '',
    demographics: icpParsed.demographics || {},
    psychographics: icpParsed.psychographics || {},
    content_preferences: icpParsed.content_preferences || {},
    competitors: icpParsed.competitors || [],
    content_opportunities: icpParsed.content_opportunities || [],
    recommended_hashtags: icpParsed.recommended_hashtags || [],
    raw_research: icpContent
  }
};

const input = $input.item.json;
const authData = $('Auth OK?').item.json;

let themeContent = '';
try {
  themeContent = input.content[0].text;
} catch(e) {
  themeContent = JSON.stringify(input);
}

let themes = [];
try {
  themes = JSON.parse(themeContent);
} catch(e) {
  const match = themeContent.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    themes = JSON.parse(match[0]);
  } else {
    themes = [{ error: 'Could not parse themes', raw: themeContent }];
  }
}

// Group into 4 weekly themes
const weeklyThemes = {};
for (const day of themes) {
  const weekNum = day.week_number || 1;
  if (!weeklyThemes[weekNum]) {
    weeklyThemes[weekNum] = {
      week_number: weekNum,
      theme_name: day.weekly_show_name || 'Week ' + weekNum,
      theme_description: '',
      show_concept: day.weekly_show_name || '',
      hook: day.hook || '',
      content_types: []
    };
  }
  weeklyThemes[weekNum].content_types.push({
    day_number: day.day_number,
    date: day.date,
    day_of_week: day.day_of_week,
    theme: day.theme,
    content_type: day.content_type,
    platform: day.platform,
    secondary_platform: day.secondary_platform,
    hook: day.hook,
    cta: day.cta,
    hashtags: Array.isArray(day.hashtags) ? day.hashtags.join(', ') : (day.hashtags || ''),
    notes: day.notes
  });
}

const month = authData.body?.month || new Date().toISOString().slice(0, 7);
const userId = authData.user_id;

return {
  json: {
    user_id: userId,
    month: month,
    weekly_themes: Object.values(weeklyThemes),
    raw_themes: themes
  }
};

const deleteResult = $input.item.json;
const parseData = $('Parse & Group Themes').item.json;
const campaignData = $('Supabase -- UPSERT Campaign').item.json;

const campaignId = Array.isArray(campaignData) ? campaignData[0].id : campaignData.id;
const userId = parseData.user_id;
const weeklyThemes = parseData.weekly_themes;

const themeRows = weeklyThemes.map(wt => ({
  user_id: userId,
  campaign_id: campaignId,
  week_number: wt.week_number,
  theme_name: wt.theme_name,
  theme_description: wt.theme_description || '',
  show_concept: wt.show_concept || '',
  hook: wt.hook || '',
  content_types: wt.content_types
}));

return { json: { theme_rows: themeRows, campaign_id: campaignId, user_id: userId } };

const input = $input.item.json;
const items = Array.isArray(input) ? input : [input];

if (!items || items.length === 0 || (items.length === 1 && !items[0].id)) {
  return {
    json: {
      success: true,
      count: 0,
      themes: []
    }
  };
}

const themes = items.map(item => ({
  id: item.id || '',
  week_number: item.week_number || '',
  theme_name: item.theme_name || '',
  theme_description: item.theme_description || '',
  show_concept: item.show_concept || '',
  hook: item.hook || '',
  content_types: item.content_types || [],
  campaign: item.campaigns || null,
  created_at: item.created_at || ''
}));

return {
  json: {
    success: true,
    count: themes.length,
    themes: themes
  }
};

const today = new Date().toISOString().split('T')[0];
const input = $input.item.json;

return {
  json: {
    date: today,
    trigger_source: input.body ? 'webhook' : 'cron',
    user_id: input.user_id || '',
    webhook_data: input.body || null
  }
};

const today = new Date().toISOString().split('T')[0];
const triggerData = $('Merge Trigger Sources').item.json;
const themesRaw = $input.item.json;
const themes = Array.isArray(themesRaw) ? themesRaw : [themesRaw];

// Flatten weekly themes into daily content items
const dailyItems = [];
for (const theme of themes) {
  if (!theme.content_types || !Array.isArray(theme.content_types)) continue;
  for (const ct of theme.content_types) {
    dailyItems.push({
      ...ct,
      theme_id: theme.id,
      campaign_id: theme.campaign_id,
      user_id: triggerData.user_id,
      weekly_show_name: theme.theme_name || theme.show_concept || '',
      week_number: theme.week_number
    });
  }
}

// Filter to today's content if trigger is cron, otherwise use webhook body
let filteredItems = dailyItems;
if (triggerData.trigger_source === 'cron') {
  filteredItems = dailyItems.filter(item => item.date === today);
}

if (filteredItems.length === 0) {
  filteredItems = dailyItems.length > 0
    ? [dailyItems[0]]
    : [{ theme: 'General engagement post', content_type: 'Value', platform: 'LinkedIn', user_id: triggerData.user_id }];
}

return filteredItems.map(item => ({ json: item }));

// PIPE-07 FIX: Normalize content_type BEFORE the Switch node
// Claude generates: Hook, Value, Proof, Carousel, Video, Engagement, Cliffhanger
// Normalize to: text, image, video, carousel
const item = $input.item.json;
const ct = (item.content_type || '').toLowerCase().trim();

item.original_content_type = item.content_type;

if (ct.includes('video') || ct.includes('reel')) {
  item.content_type = 'video';
} else if (ct.includes('carousel') || ct.includes('thread')) {
  item.content_type = 'carousel';
} else if (ct.includes('image')) {
  item.content_type = 'image';
} else {
  item.content_type = 'text';
}

return { json: item };

