// Merge all content from text/image/video/carousel branches
const item = $input.item.json;
let content = '';
let contentType = 'text';

try {
  if (item.content && item.content[0]) {
    content = item.content[0].text;
  } else if (item.data && item.data.taskId) {
    content = JSON.stringify(item);
    contentType = 'image';
  } else {
    content = JSON.stringify(item);
  }
} catch(e) {
  content = JSON.stringify(item);
}

// Get the original data from before the Switch
const normalizeData = $('Normalize Content Type').item.json;

return {
  json: {
    user_id: normalizeData.user_id || '',
    campaign_id: normalizeData.campaign_id || null,
    theme_id: normalizeData.theme_id || null,
    title: normalizeData.theme || normalizeData.weekly_show_name || 'Generated Content',
    content: content,
    content_type: normalizeData.content_type || 'text',
    platform: (normalizeData.platform || 'linkedin').toLowerCase(),
    scheduled_date: normalizeData.date || null,
    status: 'pending_review',
    image_url: null,
    video_url: null,
    image_prompt: normalizeData.theme || ''
  }
};

// Fallback handler for unmatched content types
const item = $input.item.json;
return {
  json: {
    user_id: item.user_id || '',
    campaign_id: item.campaign_id || null,
    theme_id: item.theme_id || null,
    title: item.theme || 'Fallback Content',
    content: JSON.stringify({ note: 'Content type not matched by Switch', original_type: item.original_content_type, normalized_type: item.content_type }),
    content_type: item.content_type || 'text',
    platform: (item.platform || 'linkedin').toLowerCase(),
    scheduled_date: item.date || null,
    status: 'pending_review',
    image_url: null,
    video_url: null,
    image_prompt: ''
  }
};

const authData = $input.item.json;
const body = authData.body || {};

// Normalize content_type to DB CHECK constraint values
const rawType = (body.content_type || 'text').toLowerCase().trim();
let contentType = 'text';
if (rawType.includes('video') || rawType.includes('reel')) contentType = 'video';
else if (rawType.includes('carousel') || rawType.includes('thread')) contentType = 'carousel';
else if (rawType.includes('image')) contentType = 'image';
else contentType = 'text';

// Normalize platform to DB CHECK constraint values
const rawPlatform = (body.platform || 'linkedin').toLowerCase().trim();
let platform = 'linkedin';
if (rawPlatform.includes('instagram')) platform = 'instagram';
else if (rawPlatform.includes('x') || rawPlatform.includes('twitter')) platform = 'x';
else if (rawPlatform.includes('youtube')) platform = 'youtube';
else platform = 'linkedin';

return {
  json: {
    user_id: authData.user_id,
    title: body.title || body.theme || 'Untitled Post',
    content: body.content || body.post_text || '',
    content_type: contentType,
    platform: platform,
    scheduled_date: body.scheduled_date || body.scheduled_for || null,
    status: 'pending_review',
    image_url: body.image_url || null,
    video_url: body.video_url || null,
    image_prompt: body.image_prompt || '',
    campaign_id: body.campaign_id || null,
    theme_id: body.theme_id || null
  }
};

const items = $input.item.json;

// Supabase returns an array of content_items for this user
// Handle both array response (direct) and wrapped response
const allItems = Array.isArray(items) ? items : (items.body || items.data || [items]);

// Handle empty response
if (!allItems || allItems.length === 0 || (allItems.length === 1 && !allItems[0].id)) {
  return { json: {
    success: true,
    stats: { pending_review: 0, pending: 0, approved: 0, rejected: 0, published: 0, draft: 0, total: 0 },
    pending_review: [],
    pending: [],
    approved: [],
    rejected: [],
    published: [],
    draft: [],
    all: []
  } };
}

const pending_review = allItems.filter(i => i.status === 'pending_review');
const approved = allItems.filter(i => i.status === 'approved');
const rejected = allItems.filter(i => i.status === 'rejected');
const published = allItems.filter(i => i.status === 'published');
const draft = allItems.filter(i => i.status === 'draft');

return { json: {
  success: true,
  stats: {
    pending_review: pending_review.length,
    pending: pending_review.length,
    approved: approved.length,
    rejected: rejected.length,
    published: published.length,
    draft: draft.length,
    total: allItems.length
  },
  pending_review: pending_review,
  pending: pending_review,
  approved: approved,
  rejected: rejected,
  published: published,
  draft: draft,
  all: allItems
} };

const deleted = $input.item.json;

// Supabase DELETE with Prefer: return=representation returns array of deleted rows
const deletedItems = Array.isArray(deleted) ? deleted : (deleted.body || []);
const count = Array.isArray(deletedItems) ? deletedItems.length : 0;

return { json: {
  success: true,
  message: 'Pending content cleared',
  deleted_count: count
} };

const webhookData = $('Phase 3 -- Webhook Trigger').first().json;
const input = $input.item.json;

// Supabase returns array of approved content_items
const items = Array.isArray(input) ? input : (input.body || input.data || [input]);

// Get approved content_ids from the frontend request body (if filtering specific items)
const approvedIds = webhookData.body?.content_ids || [];

const platformTimes = {
  'linkedin': { hour: 9, minute: 0 },
  'instagram': { hour: 12, minute: 30 },
  'x': { hour: 15, minute: 0 },
  'youtube': { hour: 14, minute: 0 },
  'facebook': { hour: 10, minute: 0 },
  'tiktok': { hour: 19, minute: 0 }
};

const platformColors = {
  'linkedin': '9',
  'instagram': '4',
  'x': '7',
  'youtube': '11',
  'facebook': '9',
  'tiktok': '2'
};

// Filter to specific items if content_ids provided
let filteredItems = items;
if (approvedIds.length > 0) {
  filteredItems = items.filter(item => approvedIds.includes(item.id));
}

if (!filteredItems || filteredItems.length === 0) {
  return [{ json: { _noEvents: true, success: true, phase: 3, message: 'No approved items to sync', events_created: 0 } }];
}

const output = filteredItems.map(item => {
  const platform = (item.platform || 'linkedin').toLowerCase();
  const times = platformTimes[platform] || { hour: 9, minute: 0 };
  const dateStr = item.scheduled_date || new Date().toISOString().split('T')[0];

  const startTime = dateStr + 'T' + String(times.hour).padStart(2, '0') + ':' + String(times.minute).padStart(2, '0') + ':00';
  const endHour = times.hour + 1;
  const endTime = dateStr + 'T' + String(endHour).padStart(2, '0') + ':' + String(times.minute).padStart(2, '0') + ':00';

  const title = item.title || item.content_type || 'Post';

  return {
    json: {
      summary: '[' + platform.charAt(0).toUpperCase() + platform.slice(1) + '] ' + title,
      description: 'Content Type: ' + (item.content_type || '') + '\nPlatform: ' + platform + '\n\nContent: ' + (item.content || '').substring(0, 500) + '\n\n---\nGenerated by ELUXR Social Media Agent',
      startTime: startTime,
      endTime: endTime,
      colorId: platformColors[platform] || '9',
      content_id: item.id
    }
  };
});

return output;

const body = $input.item.json.body;
const phase = body.phase || 1;
const message = body.message || '';
const context = body.context || {};

const systemPrompts = {
  1: 'You are the ELUXR Business Analyzer AI assistant. You help users analyze their business, build ICPs (Ideal Customer Profiles), and perform market research. You have access to their business data and provide actionable insights for social media content strategy. Be specific, data-driven, and strategic.',
  2: 'You are the ELUXR Theme Engine AI assistant. You help users create 30-day content themes using the Netflix model -- 4 weekly "shows" with hooks, variety, and audience retention. You understand content cyclicity, platform-specific strategies, and engagement psychology. Help them refine weekly themes and daily content plans.',
  3: 'You are the ELUXR Content Calendar AI assistant. You help users manage their 30-day content calendar, reschedule posts, swap themes between days, add special events, and optimize posting times. You know optimal posting times for each platform and can suggest schedule adjustments based on engagement patterns.',
  4: 'You are the ELUXR Content Studio AI assistant. You help users write social media posts, generate image prompts for Nano Banana Pro, create video scripts, and repurpose content across platforms. You write in the user\'s brand voice and optimize for each platform\'s algorithm and best practices.',
  5: 'You are the ELUXR Approval Queue AI assistant. You help users review pending content, suggest edits, approve or reject posts in bulk, and manage the publishing pipeline. You can summarize pending items, flag potential issues, and recommend improvements before publishing.',
  6: 'You are the ELUXR Image Generation AI assistant specializing in Nano Banana Pro prompts. You help users craft optimal image prompts, suggest styles, aspect ratios, and refinements. You understand composition rules, social media visual best practices, and platform-specific image requirements.',
  7: 'You are the ELUXR Video Script AI assistant. You help users generate video ideas, create camera-ready scripts with hooks/setup/value/CTA structure, suggest B-roll, on-screen text cues, and thumbnail ideas. You understand short-form video psychology and platform algorithms.'
};

return { json: {
  phase: phase,
  message: message,
  system_prompt: systemPrompts[phase] || systemPrompts[1],
  context: context
} };

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'Content-Type': 'application/json',
    'anthropic-version': '2023-06-01',
    'x-api-key': $env.get('ANTHROPIC_API_KEY') || ''
  },
  body: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 2048,
    system: $input.item.json.system_prompt,
    messages: [{role: 'user', content: $input.item.json.message}]
  }
});

return {json: response};

const body = $input.item.json.body;
const prompt = body.prompt || 'Professional social media graphic';
const aspectRatio = body.aspect_ratio || '1:1';
const style = body.style || 'photorealistic';

const dimensions = {
  '1:1': { width: 1024, height: 1024 },
  '16:9': { width: 1920, height: 1080 },
  '9:16': { width: 1080, height: 1920 },
  '4:3': { width: 1024, height: 768 }
};

const dim = dimensions[aspectRatio] || dimensions['1:1'];

return {
  json: {
    prompt: `${style} style: ${prompt}`,
    width: dim.width,
    height: dim.height,
    aspect_ratio: aspectRatio,
    style: style
  }
};

const item = $input.item.json;
return {
  json: {
    ...item,
    pollCount: 0,
    taskId: item.data?.task_id || item.data?.taskId || item.task_id || item.taskId
  }
};

const result = $input.item.json;
const pollCount = (result.pollCount || 0) + 1;

const state = result.data?.state || result.state || 'processing';
const isReady = state === 'success' || state === 'completed';
const isTimeout = pollCount >= 12;
const isError = state === 'failed' || state === 'error';

return {
  json: {
    ...result,
    pollCount,
    isComplete: isReady || isTimeout || isError,
    isSuccess: isReady,
    error: isTimeout ? 'Image generation timed out after 65 seconds' :
           isError ? `Image generation failed: ${state}` : null
  }
};

const result = $input.item.json;

let imageUrl = '';

if (result.data && result.data.resultJson) {
  try {
    const parsed = JSON.parse(result.data.resultJson);
    if (parsed.resultUrls && parsed.resultUrls.length > 0) {
      imageUrl = parsed.resultUrls[0];
    }
  } catch(e) {
    // fallback
  }
}

return {
  json: {
    success: !!imageUrl,
    image_url: imageUrl,
    taskId: result.data?.taskId || result.taskId || ''
  }
};

const input = $input.item.json;
let script = '';
try {
  script = input.content[0].text;
} catch(e) {
  script = JSON.stringify(input);
}

let parsed = {};
try {
  parsed = JSON.parse(script);
} catch(e) {
  const match = script.match(/\{[\s\S]*\}/);
  if (match) parsed = JSON.parse(match[0]);
  else parsed = { raw: script };
}

return { json: { success: true, tool: 'video_script', script: parsed } };

const body = $input.item.json.body;
const imageUrl = body.image_url || '';
const prompt = body.prompt || 'Professional UGC-style promotional video';
const aspectRatio = body.aspect_ratio || '9:16';
const platform = body.platform || 'Instagram Reels';

const dimensions = {
  '9:16': { width: 720, height: 1280 },
  '16:9': { width: 1280, height: 720 },
  '1:1': { width: 720, height: 720 }
};

const dim = dimensions[aspectRatio] || dimensions['9:16'];

return {
  json: {
    image_url: imageUrl,
    prompt: prompt,
    aspect_ratio: aspectRatio,
    width: dim.width,
    height: dim.height,
    platform: platform
  }
};

const result = $input.item.json;

let videoUrl = '';

if (result.data && result.data.resultJson) {
  try {
    const parsed = JSON.parse(result.data.resultJson);
    if (parsed.resultUrls && parsed.resultUrls.length > 0) {
      videoUrl = parsed.resultUrls[0];
    }
  } catch(e) {}
}

return {
  json: {
    success: !!videoUrl,
    video_url: videoUrl,
    taskId: result.data?.taskId || result.taskId || ''
  }
};
